// Mock IdP directory. Real deployment: Okta/Entra Graph call.
const DIRECTORY = {
  'j.smith':    { role: 'Finance Analyst', department: 'Finance', mfa: true,  recent_countries: ['TR'], service_account: false, last_password_change_days: 42 },
  'a.yilmaz':   { role: 'HR Specialist',   department: 'HR',      mfa: true,  recent_countries: ['TR'], service_account: false, last_password_change_days: 12 },
  'c.demir':    { role: 'Senior Engineer', department: 'R&D',     mfa: true,  recent_countries: ['TR','DE'], service_account: false, last_password_change_days: 190 },
  'svc-backup': { role: 'Service Account', department: 'IT',      mfa: false, recent_countries: ['TR'], service_account: true,  last_password_change_days: 400 },
};
const user = String(query).trim().toLowerCase().replace(/@.*$/, '');
const rec = DIRECTORY[user];
return rec ? JSON.stringify({ user, ...rec }) : JSON.stringify({ user, error: 'not found in directory' });

// Mock EDR/asset data. Real deployment: CrowdStrike /devices/queries + /detects.
const HOSTS = {
  'wks-fin-042': { os: 'Windows 11', owner: 'j.smith', criticality: 'standard', edr_sensor: 'healthy', detections_30d: 0, internet_facing: false },
  'srv-ad-01':   { os: 'Windows Server 2022', owner: 'infrastructure', criticality: 'crown-jewel', edr_sensor: 'healthy', detections_30d: 2, internet_facing: false },
  'web-prod-03': { os: 'Ubuntu 22.04', owner: 'platform', criticality: 'high', edr_sensor: 'degraded', detections_30d: 1, internet_facing: true },
};
const host = String(query).trim().toLowerCase();
const rec = HOSTS[host];
return rec ? JSON.stringify({ host, ...rec }) : JSON.stringify({ host, error: 'not in inventory — treat as unmanaged device' });

// Mock case archive. Real deployment: TheHive/Jira JQL search.
const ARCHIVE = [
  { case_id: 'SOC-2231', rule: 'Encoded PowerShell', entity: 'wks-fin-042', disposition: 'false_positive', note: 'SCCM deployment script, recurring weekly' },
  { case_id: 'SOC-2198', rule: 'Multiple Failed Logins Followed by Success', entity: 'svc-backup', disposition: 'benign_true_positive', note: 'stale password on backup appliance after rotation' },
  { case_id: 'SOC-2140', rule: 'Encoded PowerShell', entity: 'srv-ad-01', disposition: 'true_positive', note: 'Cobalt Strike stager, IR case opened' },
];
const term = String(query).trim().toLowerCase();
const hits = ARCHIVE.filter(c => c.rule.toLowerCase().includes(term) || c.entity.toLowerCase().includes(term)).slice(0, 3);
return hits.length ? JSON.stringify(hits) : JSON.stringify({ result: 'no similar past cases found' });

// The agent's output is advisory. Validate the parsed structure and count
// tool usage from intermediate steps for the audit trail.
const alert = $('Normalize Alert').item.json;
const out = $json.output ?? {};
const steps = $json.intermediateSteps ?? [];
const allowed = ['true_positive', 'false_positive', 'benign_true_positive', 'needs_review'];
const valid = out && allowed.includes(out.verdict);
// Strip Slack-active characters from agent prose (injection defense).
const clean = s => String(s ?? '').replace(/[<>@]/g, '').slice(0, 600);

const toolTrail = steps.map(s => ({
  tool: s.action?.tool ?? 'unknown',
  input: typeof s.action?.toolInput === 'string' ? s.action.toolInput.slice(0, 120) : JSON.stringify(s.action?.toolInput ?? {}).slice(0, 120),
})).slice(0, 10);

return { json: {
  ...alert,
  verdict: valid ? out.verdict : 'needs_review',
  confidence: valid ? Math.min(100, Math.max(0, Number(out.confidence) || 0)) : 0,
  rationale: valid ? clean(out.rationale) : 'Agent output failed schema validation (or the agent run failed) — routed to analyst review.',
  evidence: valid && Array.isArray(out.evidence) ? out.evidence.map(e => ({ tool: clean(e?.tool).slice(0, 40), finding: clean(e?.finding) })) : [],
  mitre_techniques: valid && Array.isArray(out.mitre_techniques) ? out.mitre_techniques.map(t => ({ id: clean(t?.id).slice(0, 12), name: clean(t?.name) })) : [],
  recommended_actions: valid && Array.isArray(out.recommended_actions) ? out.recommended_actions.map(clean) : [],
  open_questions: valid && Array.isArray(out.open_questions) ? out.open_questions.map(clean) : [],
  tool_calls_made: toolTrail.length,
  tool_trail: toolTrail,
} };

